import { useState } from "react";
import { useTTS } from "../../hooks/useSpeech";

export default function StorySection({ story, onDone, done }) {
  const { speak, stop, speaking } = useTTS();
  const [showComp, setShowComp] = useState(false);
  const [answers, setAnswers] = useState({});
  const [checked, setChecked] = useState(false);

  function togglePlay() {
    if (speaking) stop();
    else speak(story.body.replace(/\n/g, " "), 0.9);
  }

  function checkAnswers() { setChecked(true); }

  const allCorrect = story.comprehension?.every((q, i) => answers[i] === q.ans);

  return (
    <div className="fade-in">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-playfair text-xl text-gray-200">{story.title}</h3>
        <button onClick={togglePlay}
          className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-bold border-2 transition-all
            ${speaking ? "bg-blue-900 text-white border-blue-900" : " text-slate-700 border-gray-700 hover:border-blue-900 hover:text-blue-900"}`}>
          {speaking ? "⏹ Stop" : "🔊 Listen"}
        </button>
      </div>

      <div className="bg-[#221f35] border border-gray-700 rounded-2xl p-5 text-sm leading-8 space-y-1 mb-4">
        {story.body.split("\n").map((p, i) => p.trim() ? <p key={i}>{p}</p> : <br key={i} />)}
      </div>

      <div className="flex flex-wrap gap-2 mb-4">
        {story.tags?.map((t, i) => (
          <span key={i} className="text-xs font-bold bg-blue-100 text-blue-800 px-3 py-1 rounded-lg">{t}</span>
        ))}
      </div>

      {/* Comprehension */}
      {story.comprehension && (
        <div className="border-t border-slate-200 pt-4">
          <button onClick={() => setShowComp((s) => !s)}
            className="text-sm font-bold  hover:underline mb-3">
            {showComp ? "▲ Hide" : "▼ Show"} Comprehension Questions
          </button>
          {showComp && (
            <div className="space-y-4 fade-in">
              {story.comprehension.map((cq, i) => (
                <div key={i}>
                  <p className="text-sm font-bold text-slate-800 mb-2">{i + 1}. {cq.q}</p>
                  <div className="grid grid-cols-2 gap-2">
                    {cq.opts.map((opt, j) => {
                      let cls = "text-left px-3 py-2 rounded-lg text-xs font-bold border-2 cursor-pointer transition-all ";
                      if (!checked) cls += answers[i] === j ? "border-blue-900 bg-blue-50 text-blue-900" : "border-slate-200 bg-white text-slate-600 hover:border-blue-300";
                      else if (j === cq.ans) cls += "border-green-500 bg-green-50 text-green-700";
                      else if (answers[i] === j) cls += "border-red-400 bg-red-50 text-red-700";
                      else cls += "border-slate-100 bg-slate-50 text-slate-400 opacity-50";
                      return (
                        <button key={j} className={cls} onClick={() => !checked && setAnswers((a) => ({ ...a, [i]: j }))}>
                          {opt}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
              {!checked && Object.keys(answers).length === story.comprehension.length && (
                <button onClick={checkAnswers}
                  className="bg-indigo-700 text-white px-5 py-2 rounded-xl text-sm font-bold hover:bg-indigo-600 transition-all">
                  Check Answers
                </button>
              )}
              {checked && (
                <p className={`text-sm font-bold ${allCorrect ? "text-green-700" : "text-orange-600"}`}>
                  {allCorrect ? "🎉 All correct! Great reading!" : "📖 Review the story and try again!"}
                </p>
              )}
            </div>
          )}
        </div>
      )}

      {!done ? (
        <div className="flex justify-end mt-5">
          <button onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5">
            Mark as Done ✓
          </button>
        </div>
      ) : <p className="text-right text-green-700 font-bold text-sm mt-4">✓ Story completed!</p>}
    </div>
  );
}
